SUPPORTED_NETWORKS = sorted(set(_BRAND_PATHS) | set(_GENERIC_OUTLINE))


# Official brand colours (LinkedIn blue, GitHub near-black, Gmail-style
# red mail, etc.). At 9–11pt these read as accents rather than noise;
# without them the contact line looks generic.
#
# Sources: Simple Icons brand guidelines + each company's official
# colour. Generic icons (mail/phone/web/link) get neutral inks.
BRAND_COLOR: dict[str, str] = {
    "linkedin":      "#0A66C2",
    "github":        "#181717",
    "gitlab":        "#FC6D26",
    "x":             "#000000",
    "twitter":       "#000000",
    "mastodon":      "#6364FF",
    "bluesky":       "#0085FF",
    "instagram":     "#E4405F",
    "youtube":       "#FF0000",
    "telegram":      "#26A5E4",
    "whatsapp":      "#25D366",
    "reddit":        "#FF4500",
    "stackoverflow": "#F58025",
    "leetcode":      "#FFA116",
    "orcid":         "#A6CE39",
    "googlescholar": "#4285F4",
    "researchgate":  "#00CCBB",
    "imdb":          "#F5C518",
    # Generic icons — Gmail-style red for mail (matches the look of the
    # reference PDF), neutral inks for phone/web/link.
    "mail":          "#EA4335",
    "phone":         "#374151",
    "web":           "#0866FF",
    "link":          "#0866FF",
}


def color_for(name: str) -> str | None:
    """Return the brand colour hex for a known network, else None."""
    key = normalise(name)
    return BRAND_COLOR.get(key) if key else None


def normalise(name: str) -> str | None:
    """Map a user-supplied network string to a canonical icon key, or None."""
    if not name:
        return None
    key = name.strip().lower().replace("_", "")
    key = ALIASES.get(key, key)
    if key in _BRAND_PATHS or key in _GENERIC_OUTLINE:
        return key
    # Allow space/dash variants
    flat = key.replace(" ", "").replace("-", "")
    return flat if flat in _BRAND_PATHS or flat in _GENERIC_OUTLINE else None


def svg_for(name: str, size: int = 12, *, mono: bool = False) -> str:
    """Return an inline SVG string for the named icon, or empty if unknown.

    Args:
        name: Network identifier (canonical or alias).
        size: Icon size in pixels (or pt, since we use the same number for both).
        mono: If True, fill with ``currentColor`` for a monochrome look.
            Default False — the icon uses its official brand colour.
    """
    key = normalise(name)
    if key is None:
        return ""
    color = "currentColor" if mono else (BRAND_COLOR.get(key) or "currentColor")
    if key in _BRAND_PATHS:
        body = f'<path fill="{color}" d="{_BRAND_PATHS[key]}"/>'
    else:
        # Generic outlines (mail/phone/web/link) are stored with explicit
        # ``fill="currentColor"`` baked in — replace it so they pick up the
        # right brand-colour or stay monochrome on demand.
        body = _GENERIC_OUTLINE[key].replace('fill="currentColor"', f'fill="{color}"')
    return (
        f'<svg class="brand-icon" xmlns="http://www.w3.org/2000/svg" '
        f'viewBox="0 0 24 24" width="{size}" height="{size}" '
        f'aria-hidden="true">{body}</svg>'
    )


def url_for(network: str, username: str | None = None, href: str | None = None) -> str:
    """Resolve the final URL for a contact entry.

    Priority: explicit ``href`` > template applied to ``username`` > empty.
    """
    if href:
        return href
    if not username:
        return ""
    key = normalise(network) or network.strip().lower()
    template = URL_TEMPLATES.get(key)
    return template.format(username) if template else username


def label_for(network: str, username: str, label: str | None = None) -> str:
    """Pick the human-readable label for a contact entry.

    Priority: explicit ``label`` > username (or stripped variant) > network.
    """
    if label:
        return label
    if username:
        key = normalise(network) or ""
        # For mail/phone/web, show the actual address; for socials, show the
        # handle (more recognisable than the full URL).
        if key in ("mail", "phone"):
            return username
        return username
    return network
